import React from 'react';
import { Jumbotron, Container, Row, Col } from 'react-bootstrap';
import styled from 'styled-components';
import posed from 'react-pose';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faGamepad } from '@fortawesome/free-solid-svg-icons';
import gamePic from '../../assets/game-img.png';
import Fade from 'react-reveal/Fade';
import Jump from 'react-reveal/Jump';
import { HeaderJumbotron } from '../HeaderJumbotron';
import { Link } from 'react-router-dom';

const Styled = styled.div`

  .jumbo-no-margin {
    margin-bottom: 0;
  }
  h2 {
    margin-bottom: 0;
  }
  .project-tools {
    margin-left: 30px;
  }
  .project-inner {
    margin-top: 20px;
  }
  .project-img {
    width: 100%;
    border-radius: 10px;
  }
  .game-image {
    border-radius: 10px;
  }
  .centered-img-text {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
  }
  .img-text-wrapper {
    position: relative;
    text-align: center;
    color: white;
    font-size: 70px;
    text-shadow: -1px 0 black, 0 1px black, 1px 0 black, 0 -1px black;
  }
`;

const GameImage = posed.div({
  hoverable: true,
  pressable: true,
  init: {
    scale: 1,
    boxShadow: '0px 0px 0px rgba(0,0,0,0)'
  },
  hover: {
    scale: 1.025,
    boxShadow: '0px 5px 10px rgba(0,0,0,0.2)'
  },
  press: {
    scale: 1.0125,
    boxShadow: '0px 2px 5px rgba(0,0,0,0.1)'
  }
});

const PJStyles = styled.div`

`;

class ProjectJumbotron extends React.Component {
  render() {
    return (
      <PJStyles>
        <Jumbotron fluid>
          <Container>
            <h2>{this.props.name}</h2><h6 className="project-tools">{this.props.tools}</h6>
            {this.props.children}
          </Container>
        </Jumbotron>
      </PJStyles>
    );
  }
}
class ProjectImage extends React.Component {
  constructor(props) {
    super(props);
    this.handleMouseEnter = this.handleMouseEnter.bind(this);
    this.handleMouseLeave = this.handleMouseLeave.bind(this);
    this.state = { hover: false };
  }
  handleMouseEnter() {
    this.setState({ hover: true })
  }
  handleMouseLeave() {
    this.setState({ hover: false })
  }
  render() {
    return (
      <div>
        <Link to='/projects/unity'>
          <GameImage className="game-image" onMouseEnter={this.handleMouseEnter} onMouseLeave={this.handleMouseLeave}>
            <div className="img-text-wrapper">
              <img className="project-img" src={this.props.src} alt="Picture of Game" />
              <div className="centered-img-text">
                <Fade when={this.state.hover} duration={200}><span>PLAY</span></Fade>
              </div>
            </div>
          </GameImage>
        </Link>
      </div>
    );
  }
}

export class Projects extends React.Component {

  render() {
    return (
      <Styled>
      <Row>
      <Col>
        <HeaderJumbotron>
          <Fade top>
            <h1>Projects</h1>
          </Fade>
        </HeaderJumbotron>
      </Col>
      </Row>
      <Row>
      <Col>
        <ProjectJumbotron name="Unity Game" tools="C#, Unity">
          <Row>
            <Col>
              <p className="project-inner">
                Digipunk is a game that I developed this year. Implementing algorithms that I learned in class or on the internet and developing games are both a passion of mine, so I decided to combine them both into this game. The primary features that I implemented was AI through A* pathfinding and behavior trees, and procedural map generation.
              </p>
            </Col>
            <Col>
              <ProjectImage src={gamePic}/>
            </Col>
          </Row>

        </ProjectJumbotron>
      </Col>
      </Row>
      </Styled>
    );
  }
};
